const result = $input.first().json;
const rowCount = result && result.data ? result.data.length : 0;

return [{
  json: {
    status: 'success',
    message: `Synced ${rowCount} new contacts to subscribers table`,
    rowsInserted: rowCount,
    timestamp: new Date().toISOString()
  }
}];
